function calcBasePrice(size, toppings) {
  let price = 0;
  if (size === 'small') price = 10;
  else if (size === 'medium') price = 14;
  else price = 18;
  for (const t of toppings) {
    if (t === 'pepperoni') price += 2;
    else if (t === 'mushrooms') price += 1.5;
    else if (t === 'olives') price += 1;
    else if (t === 'extra cheese') price += 1.5;
  }
  return price;
}

function applyDiscounts(price, coupon) {
  if (coupon === 'WELCOME10') price *= 0.9;
  if (price > 30) price *= 0.95;
  return price;
}

function calcPizzaTotal(order) {
  const base = calcBasePrice(order.size, order.toppings);
  const afterDiscount = applyDiscounts(base, order.coupon);
  const tax = afterDiscount * 0.08;
  const delivery = order.delivery ? 3 : 0;
  return Math.round((afterDiscount + tax + delivery) * 100) / 100;
}

